#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int x, y, k, n;
void dfs(int x_, int y_, int X, int Y, int gx, int gy)
{
	if (X - x_ == 1 && Y - y_ == 1)
	{
		if (gx == x_ && gy == y_)
		{
            write(X);
            putchar(' ');
            write(Y);
            puts(" 1");
		}
		if (gx == x_ && gy == Y)
		{
			write(X);
            putchar(' ');
            write(y_);
            puts(" 2");
		}
		if (gx == X && gy == y_)
		{
			write(x_);
            putchar(' ');
            write(Y);
            puts(" 3");
		}
		if (gx == X && gy == Y)
		{
			write(x_);
            putchar(' ');
            write(y_);
            puts(" 4");
		}
		return;
	}
	int nx = (X - x_) / 2 + x_, ny = (Y - y_) / 2 + y_;
	if (gx <= nx && gy <= ny)
	{
		dfs(x_, y_, nx, ny, gx, gy);
        write(nx+1);
        putchar(' ');
        write(ny+1);
        puts(" 1");
		dfs(nx + 1, y_, X, ny, nx + 1, ny);
		dfs(nx + 1, ny + 1, X, Y, nx + 1, ny + 1);
		dfs(x_, ny + 1, nx, Y, nx, ny + 1);
	}
	if (gx <= nx && gy > ny)
	{
		dfs(x_, ny + 1, nx, Y, gx, gy);
        write(nx+1);
        putchar(' ');
        write(ny);
        puts(" 2");
		dfs(x_, y_, nx, ny, nx, ny);
		dfs(nx + 1, y_, X, ny, nx + 1, ny);
		dfs(nx + 1, ny + 1, X, Y, nx + 1, ny + 1);
	}
	if (gx > nx && gy <= ny)
	{
		dfs(nx + 1, y_, X, ny, gx, gy);
		write(nx);
        putchar(' ');
        write(ny+1);
        puts(" 3");
		dfs(nx + 1, ny + 1, X, Y, nx + 1, ny + 1);
		dfs(x_, y_, nx, ny, nx, ny);
		dfs(x_, ny + 1, nx, Y, nx, ny + 1);
	}
	if (gx > nx && gy > ny)
	{
		dfs(nx + 1, ny + 1, X, Y, gx, gy);
		write(nx);
        putchar(' ');
        write(ny);
        puts(" 4");
		dfs(x_, y_, nx, ny, nx, ny);
		dfs(x_, ny + 1, nx, Y, nx, ny + 1);
		dfs(nx + 1, y_, X, ny, nx + 1, ny);
	}
}

int main(void)
{

	cin >> k >> x >> y;
	n = 1 << k;
	dfs(1, 1, n, n, x, y);
	return false;
}
